args.query:
PREFIX cim: <https://cim.ucaiug.io/ns#>
PREFIX nc: <https://cim4.eu/ns/nc#>
SELECT ?rotatingmachineaction ?name ?mrid ?rotatingmachine ?rmName ?rmMrid WHERE {
  VALUES ?gsa { <urn:uuid:050cd458-b999-4c8d-ad24-93c6a3102b53> }
  ?gsa a nc:GridStateAlteration .
  ?gsa nc:GridStateAlterationCollection ?collection .
  ?collection a nc:GridStateAlterationCollection .
  ?collection nc:GridStateAlteration ?rotatingmachineaction .
  ?rotatingmachineaction a nc:RotatingMachineAction .
  OPTIONAL { ?rotatingmachineaction cim:IdentifiedObject.name ?name . }
  OPTIONAL { ?rotatingmachineaction cim:IdentifiedObject.mRID ?mrid . }
  OPTIONAL {
    ?rotatingmachineaction nc:RotatingMachineAction.RotatingMachine ?rotatingmachine .
    OPTIONAL { ?rotatingmachine cim:IdentifiedObject.name ?rmName . }
    OPTIONAL { ?rotatingmachine cim:IdentifiedObject.mRID ?rmMrid . }
  }
} ORDER BY ?name ?mrid

PREFIX cim: <https://cim.ucaiug.io/ns#>
PREFIX nc: <https://cim4.eu/ns/nc#>
SELECT ?collection ?collectionName ?action ?actionName ?actionMrid ?rotatingmachine ?rmName ?rmMrid WHERE {
  VALUES ?action { <urn:uuid:050cd458-b999-4c8d-ad24-93c6a3102b53> }
  ?action a nc:RotatingMachineAction .
  ?action nc:GridStateAlterationCollection ?collection .
  OPTIONAL { ?collection cim:IdentifiedObject.name ?collectionName . }
  OPTIONAL {
    ?collection nc:GridStateAlteration ?otherAction .
    ?otherAction a nc:RotatingMachineAction .
    FILTER(?otherAction != ?action)
    BIND(?otherAction AS ?action)
    OPTIONAL { ?otherAction cim:IdentifiedObject.name ?actionName . }
    OPTIONAL { ?otherAction cim:IdentifiedObject.mRID ?actionMrid . }
    OPTIONAL {
      ?otherAction nc:RotatingMachineAction.RotatingMachine ?rotatingmachine .
      OPTIONAL { ?rotatingmachine cim:IdentifiedObject.name ?rmName . }
      OPTIONAL { ?rotatingmachine cim:IdentifiedObject.mRID ?rmMrid . }
    }
  }
}

